class Solution:
    def diffWaysToCompute(self, expression: str) -> List[int]:
        memo = {}

        def helper(expr):
            if expr in memo:
                return memo[expr]
            if expr.isdigit():
                return [int(expr)]
            res = []
            for i in range(1, len(expr)-1):
                if expr[i] in '+-*':
                    left = expr[:i]
                    right = expr[i+1:]
                    left_res = helper(left)
                    right_res = helper(right)
                    for l in left_res:
                        for r in right_res:
                            if expr[i] == '+':
                                res.append(l + r)
                            elif expr[i] == '-':
                                res.append(l - r)
                            elif expr[i] == '*':
                                res.append(l * r)
            memo[expr] = res
            return res

        return helper(expression)

